import{_ as d,o as e,c as o,ag as r}from"./chunks/framework.f-eIl1f0.js";const h=JSON.parse('{"title":"Derivation Rules","description":"","frontmatter":{},"headers":[],"relativePath":"reference/derivation-rules.md","filePath":"reference/derivation-rules.md"}'),c={name:"reference/derivation-rules.md"};function a(n,t,i,s,l,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="derivation-rules" tabindex="-1">Derivation Rules <a class="header-anchor" href="#derivation-rules" aria-label="Permalink to &quot;Derivation Rules&quot;">​</a></h1><p><code>deriveTheme()</code> transforms a ColorPalette (22 terminal colors) into a Theme (33 semantic tokens). Supports two modes: truecolor (blended) and ansi16 (direct alias).</p><h2 id="truecolor-derivation" tabindex="-1">Truecolor Derivation <a class="header-anchor" href="#truecolor-derivation" aria-label="Permalink to &quot;Truecolor Derivation&quot;">​</a></h2><p>The default mode. Uses <code>blend()</code>, <code>contrastFg()</code>, <code>desaturate()</code>, and <code>complement()</code> for smooth gradients and guaranteed contrast.</p><h3 id="pairs-28-tokens" tabindex="-1">Pairs (28 tokens) <a class="header-anchor" href="#pairs-28-tokens" aria-label="Permalink to &quot;Pairs (28 tokens)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Token</th><th>Derivation</th></tr></thead><tbody><tr><td><code>bg</code></td><td><code>background</code></td></tr><tr><td><code>fg</code></td><td><code>foreground</code></td></tr><tr><td><code>surface</code></td><td><code>blend(background, foreground, 0.05)</code></td></tr><tr><td><code>surfacefg</code></td><td><code>foreground</code></td></tr><tr><td><code>popover</code></td><td><code>blend(background, foreground, 0.08)</code></td></tr><tr><td><code>popoverfg</code></td><td><code>foreground</code></td></tr><tr><td><code>muted</code></td><td><code>blend(background, foreground, 0.04)</code></td></tr><tr><td><code>mutedfg</code></td><td><code>blend(foreground, background, 0.7)</code></td></tr><tr><td><code>primary</code></td><td><code>yellow</code> (dark) / <code>blue</code> (light)</td></tr><tr><td><code>primaryfg</code></td><td><code>contrastFg(primary)</code></td></tr><tr><td><code>secondary</code></td><td><code>desaturate(primary, 0.4)</code></td></tr><tr><td><code>secondaryfg</code></td><td><code>contrastFg(secondary)</code></td></tr><tr><td><code>accent</code></td><td><code>complement(primary)</code></td></tr><tr><td><code>accentfg</code></td><td><code>contrastFg(accent)</code></td></tr><tr><td><code>error</code></td><td><code>red</code></td></tr><tr><td><code>errorfg</code></td><td><code>contrastFg(red)</code></td></tr><tr><td><code>warning</code></td><td><code>yellow</code></td></tr><tr><td><code>warningfg</code></td><td><code>contrastFg(yellow)</code></td></tr><tr><td><code>success</code></td><td><code>green</code></td></tr><tr><td><code>successfg</code></td><td><code>contrastFg(green)</code></td></tr><tr><td><code>info</code></td><td><code>cyan</code></td></tr><tr><td><code>infofg</code></td><td><code>contrastFg(cyan)</code></td></tr><tr><td><code>selection</code></td><td><code>selectionBackground</code></td></tr><tr><td><code>selectionfg</code></td><td><code>selectionForeground</code></td></tr><tr><td><code>inverse</code></td><td><code>blend(foreground, background, 0.1)</code></td></tr><tr><td><code>inversefg</code></td><td><code>contrastFg(inverse)</code></td></tr><tr><td><code>cursor</code></td><td><code>cursorColor</code></td></tr><tr><td><code>cursorfg</code></td><td><code>cursorText</code></td></tr></tbody></table><h3 id="standalone-5-tokens" tabindex="-1">Standalone (5 tokens) <a class="header-anchor" href="#standalone-5-tokens" aria-label="Permalink to &quot;Standalone (5 tokens)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Token</th><th>Derivation</th></tr></thead><tbody><tr><td><code>border</code></td><td><code>blend(background, foreground, 0.15)</code></td></tr><tr><td><code>inputborder</code></td><td><code>blend(background, foreground, 0.25)</code></td></tr><tr><td><code>focusborder</code></td><td><code>blue</code></td></tr><tr><td><code>link</code></td><td><code>blue</code></td></tr><tr><td><code>disabledfg</code></td><td><code>blend(foreground, background, 0.5)</code></td></tr></tbody></table><h3 id="palette-16-colors" tabindex="-1">Palette (16 colors) <a class="header-anchor" href="#palette-16-colors" aria-label="Permalink to &quot;Palette (16 colors)&quot;">​</a></h3><p>Direct passthrough of the 16 ANSI colors: <code>[black, red, green, yellow, blue, magenta, cyan, white, brightBlack, ..., brightWhite]</code>.</p><h2 id="ansi-16-derivation" tabindex="-1">ANSI 16 Derivation <a class="header-anchor" href="#ansi-16-derivation" aria-label="Permalink to &quot;ANSI 16 Derivation&quot;">​</a></h2><p>The <code>ansi16</code> mode uses direct aliases instead of blending. Useful for terminals with limited color support.</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deriveTheme</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(palette, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ansi16&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Key differences from truecolor:</p><table tabindex="0"><thead><tr><th>Token</th><th>Truecolor</th><th>ANSI 16</th></tr></thead><tbody><tr><td><code>surface</code></td><td>blended 5% toward fg</td><td><code>black</code></td></tr><tr><td><code>popover</code></td><td>blended 8% toward fg</td><td><code>black</code></td></tr><tr><td><code>muted</code></td><td>blended 4% toward fg</td><td><code>black</code></td></tr><tr><td><code>mutedfg</code></td><td>blended 70% toward bg</td><td><code>white</code></td></tr><tr><td><code>secondary</code></td><td>desaturated primary</td><td><code>magenta</code></td></tr><tr><td><code>accent</code></td><td>complement of primary</td><td><code>cyan</code></td></tr><tr><td><code>error</code></td><td><code>red</code></td><td><code>brightRed</code> (dark) / <code>red</code> (light)</td></tr><tr><td><code>success</code></td><td><code>green</code></td><td><code>brightGreen</code> (dark) / <code>green</code> (light)</td></tr><tr><td><code>inverse</code></td><td>blended fg toward bg</td><td><code>brightWhite</code></td></tr><tr><td><code>border</code></td><td>blended 15% toward fg</td><td><code>brightBlack</code></td></tr><tr><td><code>inputborder</code></td><td>blended 25% toward fg</td><td><code>brightBlack</code></td></tr><tr><td><code>disabledfg</code></td><td>blended 50% toward bg</td><td><code>brightBlack</code></td></tr></tbody></table><p>All <code>*fg</code> contrast tokens use <code>black</code> in ansi16 mode (instead of WCAG <code>contrastFg()</code>).</p><h2 id="color-utilities" tabindex="-1">Color Utilities <a class="header-anchor" href="#color-utilities" aria-label="Permalink to &quot;Color Utilities&quot;">​</a></h2><p>The derivation pipeline uses these utilities from <code>color.ts</code>:</p><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Purpose</th></tr></thead><tbody><tr><td><code>blend(a, b, t)</code></td><td><code>(string, string, number) -&gt; string</code></td><td>Linear RGB interpolation (t=0 returns a, t=1 returns b)</td></tr><tr><td><code>contrastFg(bg)</code></td><td><code>(string) -&gt; &quot;#000000&quot; | &quot;#FFFFFF&quot;</code></td><td>WCAG-based black/white contrast pick</td></tr><tr><td><code>desaturate(color, amount)</code></td><td><code>(string, number) -&gt; string</code></td><td>Reduce saturation via HSL (amount=0.4 reduces by 40%)</td></tr><tr><td><code>complement(color)</code></td><td><code>(string) -&gt; string</code></td><td>180-degree hue rotation via HSL</td></tr><tr><td><code>brighten(color, amount)</code></td><td><code>(string, number) -&gt; string</code></td><td>Blend toward <code>#FFFFFF</code></td></tr><tr><td><code>darken(color, amount)</code></td><td><code>(string, number) -&gt; string</code></td><td>Blend toward <code>#000000</code></td></tr></tbody></table><p>All operations work on hex color strings. Non-hex inputs (ANSI color names) pass through unchanged.</p>',20)])])}const b=d(c,[["render",a]]);export{h as __pageData,b as default};
